	public static String arrayToString(String[] arr, boolean brackets) {

		int sz = arr.length;
		if (sz == 0) {
			return "";
		}

		String resp = brackets ? "[" : "";
		for (int i = 0; i < (sz - 1); i++) {
			resp = resp + arr[i] + ",";
		}

		resp = resp + arr[sz - 1] + (brackets ? "]" : "");
		return resp;
	}

